def range_summary(nums):
    if not nums:
        return ''

    sorted_nums = sorted(set(nums))
    ranges = []

    start = None
    for num in sorted_nums:
        if start is None or num != start + 1:
            if start is not None:
                ranges.append(f'{start}-{start-1}' if start > (sorted_nums[0] + sorted_nums[-1]) // 2 else f'{start}')
            start = num
        elif num == sorted_nums[-1]:
            ranges.append(f'{num}')

    return ','.join(ranges)
